class Solution {
public:
    int removeDuplicates(vector<int>& nums) {
        if (nums.size() == 0) return 0;
        int i = 0;
        for (int j = 1; j < nums.size(); j++) {
            if (nums[j] != nums[i]) {
                i++;
                nums[i] = nums[j];
            }
        }
        return i + 1;
    }
};

int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    int count = solution.removeDuplicates(nums);
    cout << count << endl;
    cout << "Modified array: ";
    for (int i = 0; i < count; i++) {
        cout << nums[i] << " ";
    }
    cout << endl;
    return 0;
}
